def _table_to_nested(table: Table) -> TableNested:
    """Convert flat Table to nested format."""
    attrs = TableAttributes()
    _populate_table_attrs(attrs, table)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        table, _TABLE_REL_FIELDS, TableRelationshipAttributes
    )
    return TableNested(
        guid=table.guid,
        type_name=table.type_name,
        status=table.status,
        version=table.version,
        create_time=table.create_time,
        update_time=table.update_time,
        created_by=table.created_by,
        updated_by=table.updated_by,
        classifications=table.classifications,
        classification_names=table.classification_names,
        meanings=table.meanings,
        labels=table.labels,
        business_attributes=table.business_attributes,
        custom_attributes=table.custom_attributes,
        pending_tasks=table.pending_tasks,
        proxy=table.proxy,
        is_incomplete=table.is_incomplete,
        provenance_type=table.provenance_type,
        home_id=table.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _table_from_nested(nested: TableNested) -> Table:
    """Convert nested format to flat Table."""
    attrs = nested.attributes if nested.attributes is not UNSET else TableAttributes()
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _TABLE_REL_FIELDS,
        TableRelationshipAttributes,
    )
    return Table(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_table_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _table_to_nested_bytes(table: Table, serde: Serde) -> bytes:
    """Convert flat Table to nested JSON bytes."""
    return serde.encode(_table_to_nested(table))


def _table_from_nested_bytes(data: bytes, serde: Serde) -> Table:
    """Convert nested JSON bytes to flat Table."""
    nested = serde.decode(data, TableNested)
    return _table_from_nested(nested)


